'use strict';

document.addEventListener('DOMContentLoaded', () => {
    const app = document.getElementById('app');
    const tasks = [
        { id: 1, text: 'Belajar JavaScript', done: false },
        { id: 2, text: 'Buat project', done: true },
    ];
    function render() {
        app.innerHTML = tasks.map(t => {
            const cls = t.done ? 'done' : '';
            const checked = t.done ? 'checked' : '';
            return '<div class="' + cls + '">' +
                '<input type="checkbox" ' + checked + ' data-id="' + t.id + '">' +
                '<span>' + t.text + '</span>' +
                '<button data-del="' + t.id + '">\u2715</button>' +
                '</div>';
        }).join('');
    }
    render();
    app.addEventListener('click', (e) => {
        const del = e.target.closest('[data-del]');
        if (del) {
            const id = +del.dataset.del;
            const idx = tasks.findIndex(t => t.id === id);
            if (idx !== -1) tasks.splice(idx, 1);
            render();
        }
    });
    app.addEventListener('change', (e) => {
        if (e.target.type === 'checkbox') {
            const id = +e.target.dataset.id;
            const task = tasks.find(t => t.id === id);
            if (task) task.done = e.target.checked;
            render();
        }
    });
    document.getElementById('addBtn').addEventListener('click', () => {
        const input = document.getElementById('taskInput');
        if (input.value.trim()) {
            tasks.push({ id: Date.now(), text: input.value, done: false });
            input.value = '';
            render();
        }
    });
});

