    if 0 <= index < len(tasks):
        tasks[index]['done'] = True
        print(f"Tugas '{tasks[index]['title']}' selesai!")
    else:
        print("Indeks tidak valid!")

def delete_task(index):
    if 0 <= index < len(tasks):
        removed = tasks.pop(index)
        print(f"Tugas '{removed['title']}' dihapus!")
    else:
        print("Indeks tidak valid!")

