import React, { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);
  return (
    <div style={{ textAlign: 'center', padding: '40px' }}>
      <h2>Counter</h2>
      <p style={{ fontSize: '48px', fontWeight: 'bold', margin: '20px 0' }}>{count}</p>
      <button onClick={() => setCount(count + 1)} style={btnStyle}>+</button>
      <button onClick={() => setCount(count - 1)} style={btnStyle}>-</button>
      <button onClick={() => setCount(0)} style={btnStyle}>Reset</button>
    </div>
  );
}

const btnStyle = {
  padding: '10px 24px',
  margin: '0 8px',
  fontSize: '18px',
  border: 'none',
  borderRadius: '8px',
  background: '#4F46E5',
  color: 'white',
  cursor: 'pointer'
};

function TodoApp() {
  const [todos, setTodos] = useState([]);
  const [input, setInput] = useState('');

  const addTodo = () => {
    if (input.trim()) {
      setTodos([...todos, { id: Date.now(), text: input, done: false }]);
      setInput('');
    }
  };

  return (
    <div style={{ padding: '40px' }}>
      <h2>To-Do List</h2>
      <div style={{ marginBottom: '16px' }}>
        <input value={input} onChange={e => setInput(e.target.value)} style={{ padding: '8px', marginRight: '8px' }} />
        <button onClick={addTodo} style={btnStyle}>Tambah</button>
      </div>
      <ul>
        {todos.map(t => (
          <li key={t.id} style={{ textDecoration: t.done ? 'line-through' : 'none' }}>{t.text}</li>
        ))}
      </ul>
    </div>
  );
}

function App() {
  return (
    <div>
      <Counter />
      <hr />
      <TodoApp />
    </div>
  );
}

export default App;

