// === REST API - Notes App ===
const express = require('express');
const app = express();
app.use(express.json());

let notes = [
    { id: 1, title: 'Belajar Express', content: 'Membuat REST API', done: false },
    { id: 2, title: 'Belajar React', content: 'Frontend dengan React', done: false }
];
let nextId = 3;

app.get('/api/notes', (req, res) => {
    res.json({ success: true, data: notes });
});

app.get('/api/notes/:id', (req, res) => {
    const note = notes.find(n => n.id === parseInt(req.params.id));
    if (!note) return res.status(404).json({ success: false, message: 'Note not found' });
    res.json({ success: true, data: note });
});

app.post('/api/notes', (req, res) => {
    const { title, content } = req.body;
    if (!title) return res.status(400).json({ success: false, message: 'Title required' });
    const note = { id: nextId++, title, content: content || '', done: false };
    notes.push(note);
    res.status(201).json({ success: true, data: note });
});

app.put('/api/notes/:id', (req, res) => {
    const idx = notes.findIndex(n => n.id === parseInt(req.params.id));
    if (idx === -1) return res.status(404).json({ success: false, message: 'Note not found' });
    notes[idx] = { ...notes[idx], ...req.body };
    res.json({ success: true, data: notes[idx] });
});

app.delete('/api/notes/:id', (req, res) => {
    const idx = notes.findIndex(n => n.id === parseInt(req.params.id));
    if (idx === -1) return res.status(404).json({ success: false, message: 'Note not found' });
    notes.splice(idx, 1);
    res.json({ success: true, message: 'Note deleted' });
});

app.listen(3000, () => console.log('Notes API running on port 3000'));

