import java.util.ArrayList;
import java.util.Scanner;

class Student {
    String name;
    double grade;

    Student(String name, double grade) {
        this.name = name;
        this.grade = grade;
    }

    String getGradeLetter() {
        if (grade >= 85) return "A";
        else if (grade >= 70) return "B";
        else if (grade >= 60) return "C";
        else return "D";
    }

    @Override
    public String toString() {
        return name + " - " + grade + " (" + getGradeLetter() + ")";
    }
}

class StudentManager {
    private ArrayList<Student> students = new ArrayList<>();

    void addStudent(String name, double grade) {
        students.add(new Student(name, grade));
        System.out.println("Student added: " + name);
    }

    void displayAll() {
        if (students.isEmpty()) {
            System.out.println("No students.");
            return;
        }
        System.out.println();
        System.out.println("=== All Students ===");
        for (Student s : students) {
            System.out.println(s);
        }
        System.out.println("Total: " + students.size());
    }

    double getAverage() {
        if (students.isEmpty()) return 0;
        double sum = 0;
        for (Student s : students) sum += s.grade;
        return sum / students.size();
    }

    void deleteStudent(int index) {
        if (index >= 0 && index < students.size()) {
            System.out.println("Deleted: " + students.remove(index).name);
        } else {
            System.out.println("Invalid index!");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        StudentManager mgr = new StudentManager();
        Scanner sc = new Scanner(System.in);

        while (true) {
            System.out.println();
            System.out.println("=== Menu ===");
            System.out.println("1. Add Student");
            System.out.println("2. Display All");
            System.out.println("3. Average Grade");
            System.out.println("4. Delete Student");
            System.out.println("5. Exit");
            System.out.print("Choice: ");

            int choice = sc.nextInt();
            sc.nextLine();

            switch (choice) {
                case 1:
                    System.out.print("Name: ");
                    String name = sc.nextLine();
                    System.out.print("Grade: ");
                    double grade = sc.nextDouble();
                    mgr.addStudent(name, grade);
                    break;
                case 2:
                    mgr.displayAll();
                    break;
                case 3:
                    System.out.println("Average: " + mgr.getAverage());
                    break;
                case 4:
                    System.out.print("Index to delete: ");
                    int idx = sc.nextInt();
                    mgr.deleteStudent(idx);
                    break;
                case 5:
                    System.out.println("Goodbye!");
                    sc.close();
                    return;
                default:
                    System.out.println("Invalid choice!");
            }
        }
    }
}

