#include <iostream>
#include <vector>
#include <string>
#include <fstream>
using namespace std;

struct Book {
    int id;
    string title;
    string author;
    int year;
    bool available;
};

void displayBooks(const vector<Book>& books) {
    if (books.empty()) {
        cout << "No books available.\n";
        return;
    }
    cout << "\n=== Library Books ===\n";
    for (const auto& b : books) {
        cout << b.id << ". " << b.title << " by " << b.author
             << " (" << b.year << ") "
             << (b.available ? "[Available]" : "[Borrowed]") << endl;
    }
}

void addBook(vector<Book>& books) {
    Book b;
    b.id = books.size() + 1;
    cout << "Title: ";
    cin.ignore();
    getline(cin, b.title);
    cout << "Author: ";
    getline(cin, b.author);
    cout << "Year: ";
    cin >> b.year;
    b.available = true;
    books.push_back(b);
    cout << "Book added!\n";
}

int main() {
    vector<Book> books;
    int choice;

    do {
        cout << "\n=== Library System ===\n";
        cout << "1. Display Books\n";
        cout << "2. Add Book\n";
        cout << "3. Borrow Book\n";
        cout << "4. Return Book\n";
        cout << "5. Exit\n";
        cout << "Choice: ";
        cin >> choice;

        switch (choice) {
            case 1: displayBooks(books); break;
            case 2: addBook(books); break;
            case 3: {
                int id;
                cout << "Book ID to borrow: ";
                cin >> id;
                if (id > 0 && id <= books.size() && books[id-1].available) {
                    books[id-1].available = false;
                    cout << "Book borrowed!\n";
                } else cout << "Cannot borrow!\n";
                break;
            }
            case 4: {
                int id;
                cout << "Book ID to return: ";
                cin >> id;
                if (id > 0 && id <= books.size() && !books[id-1].available) {
                    books[id-1].available = true;
                    cout << "Book returned!\n";
                } else cout << "Cannot return!\n";
                break;
            }
        }
    } while (choice != 5);

    cout << "Goodbye!\n";
    return 0;
}
